import { Component, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';

@Component({
  selector: 'app-contact-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './contact-form.component.html',
  styleUrl: './contacts.css',
})
export class ContactFormComponent {
  private fb = inject(FormBuilder);
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  readonly accounts = [
    'Acme Corporation',
    'Globex Industries',
    'Initech',
    'Umbrella Health',
    'Soylent Foods',
    'Stark Energy',
    'Wayne Media',
    'Hooli Cloud',
    'Vandelay Imports',
    'Pied Piper',
  ];

  private pm = toSignal(this.route.paramMap, { initialValue: this.route.snapshot.paramMap });
  readonly editId = computed(() => this.pm().get('id'));
  readonly isEdit = computed(() => !!this.editId());

  form = this.fb.group({
    firstName: ['', [Validators.required]],
    lastName: ['', [Validators.required]],
    title: [''],
    email: ['', [Validators.required, Validators.email]],
    phone: [''],
    accountName: ['Acme Corporation', [Validators.required]],
  });

  constructor() {
    if (this.isEdit()) {
      // Prefill with representative existing values for the mockup.
      this.form.patchValue({
        firstName: 'Jane',
        lastName: 'Rivera',
        title: 'VP Operations',
        email: 'jane@acme.com',
        phone: '+1 415 555 0110',
        accountName: 'Acme Corporation',
      });
    }
  }

  save(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    const target = this.isEdit() ? ['/contacts', this.editId()] : ['/contacts'];
    this.router.navigate(target);
  }

  cancel(): void {
    this.router.navigate(this.isEdit() ? ['/contacts', this.editId()] : ['/contacts']);
  }
}
